from sympy import factorint
def ok(n):
    factors = factorint(n)
    if len(factors) != 2:
        return False
    p1, p2 = factors.keys()
    pow1 = p1**factors[p1]
    pow2 = p2**factors[p2]
    return p2 > pow1 or p1 > pow2
print([m for m in range(1, 201) if ok(m)])

